Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto children = ctx->children;
  auto ret = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    if (auto p = dynamic_cast<ast::PostfixExpressionContext*>(children[i])) {
      // 递归处理
      continue;
    }
    if (auto p = antlr4::Tree::getChildOfType(children[i])) {
      continue;
    }

    // 函数调用
    if (ctx->LeftParen(i - 1)) {
      auto node = make<CallExpr>();
      node->head = ret;

      if (auto argsCtx = ctx->argumentExpressionList()) {
        for (auto&& arg : argsCtx->assignmentExpression()) {
          node->args.push_back(self(arg));
        }
      }

      ret = node;
      continue;
    }

    // 数组下标
    if (ctx->LeftBracket(i - 1)) {
      auto node = make<BinaryExpr>();
      node->op = node->kIndex;
      node->lft = ret;

      // 找到对应的 expression
      for (unsigned j = i; j < children.size(); ++j) {
        if (auto exprCtx = dynamic_cast<ast::ExpressionContext*>(children[j])) {
          node->rht = self(exprCtx);
          i = j;
          break;
        }
      }

      ret = node;
      continue;
    }
  }

  return ret;
}

