Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto children = ctx->children;
  // 递归处理最内层
  if (auto primary = ctx->primaryExpression())
    return self(primary);

  // 递归处理 postfix 链
  auto ret = self(ctx->postfixExpression());

  // 函数调用
  if (ctx->LeftParen()) {
    auto node = make<CallExpr>();
    node->head = ret;

    if (auto argsCtx = ctx->argumentExpressionList()) {
      for (auto&& arg : argsCtx->assignmentExpression()) {
        node->args.push_back(self(arg));
      }
    }

    return node;
  }

  // 数组下标
  if (ctx->LeftBracket()) {
    auto node = make<BinaryExpr>();
    node->op = node->kIndex;
    node->lft = ret;
    node->rht = self(ctx->expression());
    return node;
  }

  return ret;
}

